qry:select.qry:xquery:
for $r in table(' 
		SELECT oi_tipohora, c_tipohora, d_tipohora,					
		oi_estructura = {%=#PARAM:@oi_estructura%}
		from tta01_tipohoras where 1 = 1
		{%? (#FILTRO:@oi_tipohora!='') {% AND oi_tipohora={%=#FILTRO:@oi_tipohora %} %} {% AND 1=1%} %}
		')/ROWS/ROW

			for $r in table(' 
					select per02_personal_emp.oi_personal_emp, e_numero_legajo, d_ape_y_nom, f_fecInicio, f_fecFin, d_novedad, 
      			      c_estado = (CASE c_estado
         					WHEN \'P\' THEN \'Pendiente\'
         					WHEN \'A\' THEN \'Aceptada\'
         					WHEN \'R\' THEN \'Rechazada\'
      					END) 
					from per01_personal, per02_personal_emp, tta04_novedades, tta04_personal, org02_estruc_pers
					where org02_estruc_pers.oi_estructura={#PARAM:@oi_estructura}
					{%? (#FILTRO:@oi_estructura!='') {% AND org02_estruc_pers.oi_estructura={%=#FILTRO:@oi_estructura %} %} {% AND 1=1%} %}
					and PER02_PERSONAL_EMP.oi_empresa = {#FILTRO:@oi_empresa} 						
					and per01_personal.oi_personal =  per02_personal_emp.oi_personal
					and tta04_personal.oi_personal_emp =  per02_personal_emp.oi_personal_emp
					and tta04_personal.oi_personal_emp =  tta04_novedades.oi_personal_emp
					and PER02_PERSONAL_EMP.oi_personal_emp = org02_estruc_pers.oi_personal_emp				
					{%? (#FILTRO:@f_des!='') {% and f_fecInicio >= \'{%= #FILTRO:@f_des%}\'%} {%   %}   %}
					{%? (#FILTRO:@f_has!='') {% and isnull(f_fecFin,DATEDIFF(day,1,\'{%= #FILTRO:@f_has %}\')) <= \'{%= #FILTRO:@f_has %}\' %} {%   %}  %}
					and oi_tipohora = {%= #PARAM:@oi_tipohora%}
					{%? (#FILTRO:@c_estado!='') {% and c_estado = {#FILTRO:@c_estado}%} {%  %}   %}
					{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) %} {%  %} %}							
						')/ROWS/ROW

for $r in table(' 
		select oi_tipohora, c_tipohora, d_tipohora, oi_estructura = {%=#PARAM:@oi_estructura%}
				from tta01_tipohoras where 1 = 1
				{%? (#FILTRO:@oi_tipohora!='') {% AND oi_tipohora={%=#FILTRO:@oi_tipohora %} %} {% AND 1=1%} %}
		')/ROWS/ROW

			for $r in table(' 
					select per02_personal_emp.oi_personal_emp, e_numero_legajo, d_ape_y_nom, f_fecInicio, f_fecFin, d_novedad, 
      			      c_estado = (CASE c_estado
         					WHEN \'P\' THEN \'Pendiente\'
         					WHEN \'A\' THEN \'Aceptada\'
         					WHEN \'R\' THEN \'Rechazada\'
      					END) 
					from per01_personal, per02_personal_emp, tta04_novedades, tta04_personal, org02_estruc_pers
					where org02_estruc_pers.oi_estructura={#PARAM:@oi_estructura}					
					and PER02_PERSONAL_EMP.oi_empresa = {#FILTRO:@oi_empresa} 						
					and per01_personal.oi_personal =  per02_personal_emp.oi_personal
					and tta04_personal.oi_personal_emp =  per02_personal_emp.oi_personal_emp
					and tta04_personal.oi_personal_emp =  tta04_novedades.oi_personal_emp
					and PER02_PERSONAL_EMP.oi_personal_emp = org02_estruc_pers.oi_personal_emp				
					{%? (#FILTRO:@f_des!='') {% and f_fecInicio >= \'{%= #FILTRO:@f_des%}\'%} {%  %}   %}
					{%? (#FILTRO:@f_has!='') {% and isnull(f_fecFin,DATEDIFF(day,1,\'{%= #FILTRO:@f_has %}\')) <= \'{%= #FILTRO:@f_has %}\' %} {%  %}  %}
					and oi_tipohora = {%= #PARAM:@oi_tipohora%}
					{%? (#FILTRO:@c_estado!='') {% and c_estado = {#FILTRO:@c_estado} %} {%  %}   %}
					{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) %} {%  %} %}								
						')/ROWS/ROW
